ToolSpec {
    name: "NotebookEdit",
    description: "Replace, insert, or delete a cell in a Jupyter notebook.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "notebook_path": { "type": "string" },
            "cell_id": { "type": "string" },
            "new_source": { "type": "string" },
            "cell_type": { "type": "string", "enum": ["code", "markdown"] },
            "edit_mode": { "type": "string", "enum": ["replace", "insert", "delete"] }
        },
        "required": ["notebook_path"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::WorkspaceWrite,
},
ToolSpec {
    name: "Sleep",
    description: "Wait for a specified duration without holding a shell process.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "duration_ms": { "type": "integer", "minimum": 0 }
        },
        "required": ["duration_ms"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "SendUserMessage",
    description: "Send a message to the user.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "message": { "type": "string" },
            "attachments": {
                "type": "array",
                "items": { "type": "string" }
            },
            "status": {
                "type": "string",
                "enum": ["normal", "proactive"]
            }
        },
        "required": ["message", "status"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "Config",
    description: "Get or set Claude Code settings.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "setting": { "type": "string" },
            "value": {
                "type": ["string", "boolean", "number"]
            }
        },
        "required": ["setting"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::WorkspaceWrite,
},
ToolSpec {
    name: "EnterPlanMode",
    description: "Enable a worktree-local planning mode override and remember the previous local setting for ExitPlanMode.",
    input_schema: json!({
        "type": "object",
        "properties": {},
        "additionalProperties": false
    }),
    required_permission: PermissionMode::WorkspaceWrite,
},
ToolSpec {
    name: "ExitPlanMode",
    description: "Restore or clear the worktree-local planning mode override created by EnterPlanMode.",
    input_schema: json!({
        "type": "object",
        "properties": {},
        "additionalProperties": false
    }),
    required_permission: PermissionMode::WorkspaceWrite,
},
ToolSpec {
    name: "StructuredOutput",
    description: "Return structured output in the requested format.",
    input_schema: json!({
        "type": "object",
        "additionalProperties": true
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "REPL",
    description: "Execute code in a REPL-like subprocess.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "code": { "type": "string" },
            "language": { "type": "string" },
            "timeout_ms": { "type": "integer", "minimum": 1 }
        },
        "required": ["code", "language"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "PowerShell",
    description: "Execute a PowerShell command with optional timeout.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "command": { "type": "string" },
            "timeout": { "type": "integer", "minimum": 1 },
            "description": { "type": "string" },
            "run_in_background": { "type": "boolean" }
        },
        "required": ["command"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "AskUserQuestion",
    description: "Ask the user a question and wait for their response.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "question": { "type": "string" },
            "options": {
                "type": "array",
                "items": { "type": "string" }
            }
        },
        "required": ["question"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "TaskCreate",
    description: "Create a background task that runs in a separate subprocess.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "prompt": { "type": "string" },
            "description": { "type": "string" }
        },
        "required": ["prompt"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "RunTaskPacket",
    description: "Create a background task from a structured task packet.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "objective": { "type": "string" },
            "scope": { "type": "string" },
            "repo": { "type": "string" },
            "branch_policy": { "type": "string" },
            "acceptance_tests": {
                "type": "array",
                "items": { "type": "string" }
            },
            "commit_policy": { "type": "string" },
            "reporting_contract": { "type": "string" },
            "escalation_policy": { "type": "string" }
        },
        "required": [
            "objective",
            "scope",
            "repo",
            "branch_policy",
            "acceptance_tests",
            "commit_policy",
            "reporting_contract",
            "escalation_policy"
        ],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "TaskGet",
    description: "Get the status and details of a background task by ID.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "task_id": { "type": "string" }
        },
        "required": ["task_id"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "TaskList",
    description: "List all background tasks and their current status.",
    input_schema: json!({
        "type": "object",
        "properties": {},
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "TaskStop",
    description: "Stop a running background task by ID.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "task_id": { "type": "string" }
        },
        "required": ["task_id"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "TaskUpdate",
    description: "Send a message or update to a running background task.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "task_id": { "type": "string" },
            "message": { "type": "string" }
        },
        "required": ["task_id", "message"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "TaskOutput",
    description: "Retrieve the output produced by a background task.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "task_id": { "type": "string" }
        },
        "required": ["task_id"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "WorkerCreate",
    description: "Create a coding worker boot session with trust-gate and prompt-delivery guards.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "cwd": { "type": "string" },
            "trusted_roots": {
                "type": "array",
                "items": { "type": "string" }
            },
            "auto_recover_prompt_misdelivery": { "type": "boolean" }
        },
        "required": ["cwd"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::DangerFullAccess,
},
ToolSpec {
    name: "WorkerGet",
    description: "Fetch the current worker boot state, last error, and event history.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "worker_id": { "type": "string" }
        },
        "required": ["worker_id"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
ToolSpec {
    name: "WorkerObserve",
    description: "Feed a terminal snapshot into worker boot detection to resolve trust gates, ready handshakes, and prompt misdelivery.",
    input_schema: json!({
        "type": "object",
        "properties": {
            "worker_id": { "type": "string" },
            "screen_text": { "type": "string" }
        },
        "required": ["worker_id", "screen_text"],
        "additionalProperties": false
    }),
    required_permission: PermissionMode::ReadOnly,
},
